import math

def calculate_triangle_area(a, b, c):
    s = (a + b + c) / 2
    return math.sqrt(s * (s - a) * (s - b) * (s - c))

def max_product_of_three(nums):
    nums.sort()
    n = len(nums)
    return max(nums[0] * nums[1] * nums[n-1], nums[n-3] * nums[n-2] * nums[n-1])

def sort_dicts(dicts_list, key_name):
    return sorted(dicts_list, key=lambda x: x[key_name])

# Example usage:
dicts = [{'name': 'Alice', 'age': 25}, {'name': 'Bob', 'age': 30}, {'name': 'Charlie', 'age': 20}]
sorted_dicts = sort_dicts(dicts, 'age')

def is_strictly_increasing(numbers):
    for i in range(len(numbers) - 1):
        if numbers[i] >= numbers[i + 1]:
            return False
    return True

from math import factorial

def calculate_factorials(numbers):
    return [factorial(num) for num in numbers]

